import{_ as t,o,c as r,ag as a}from"./chunks/framework.B_-t2C-M.js";const g=JSON.parse('{"title":"Commerce Business Logic","description":"","frontmatter":{},"headers":[],"relativePath":"guide/business-logic.md","filePath":"guide/business-logic.md"}'),i={name:"guide/business-logic.md"};function n(s,e,c,d,l,u){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="commerce-business-logic" tabindex="-1">Commerce Business Logic <a class="header-anchor" href="#commerce-business-logic" aria-label="Permalink to &quot;Commerce Business Logic&quot;">​</a></h1><p>LaraCommerce isn&#39;t just a set of CRUD endpoints; it&#39;s a complete commerce engine designed for scalability and data integrity. This page explains the internal logic of the core modules.</p><hr><h2 id="_1-checkout-lifecycle" tabindex="-1">1. Checkout Lifecycle <a class="header-anchor" href="#_1-checkout-lifecycle" aria-label="Permalink to &quot;1. Checkout Lifecycle&quot;">​</a></h2><p>The checkout process is handled by the <code>OrderService</code> and follows a strict atomic transaction flow to prevent data corruption.</p><h3 id="the-checkout-flow" tabindex="-1">The Checkout Flow: <a class="header-anchor" href="#the-checkout-flow" aria-label="Permalink to &quot;The Checkout Flow:&quot;">​</a></h3><ol><li><strong>Availability Check</strong>: The system verifies that every item in the cart is still in stock.</li><li><strong>Tax Calculation</strong>: Taxes are computed via <code>TaxService::calculate()</code> using the delivery address country/state and the <code>standard</code> tax category.</li><li><strong>Snapshotting</strong>: Prices, product names, and addresses are &quot;snapshotted&quot; into the <code>order_items</code> and <code>order_addresses</code> tables. This ensures that if a product&#39;s price changes later, the original order record remains accurate for accounting.</li><li><strong>Stock Deduction</strong>: Stock for each variant with <code>track_inventory</code> enabled is <strong>deducted</strong> from inventory via <code>InventoryService::deduct()</code>. If stock is insufficient, the entire transaction is rolled back with an <code>InsufficientStockException</code>.</li><li><strong>Coupon Usage</strong>: If a coupon was applied, usage is recorded and the coupon&#39;s <code>usage_count</code> is incremented.</li><li><strong>Cart Cleanup</strong>: The user&#39;s cart is cleared.</li><li><strong>Event Dispatch</strong>: An <code>OrderPlaced</code> event is fired, triggering emails and push notifications.</li></ol><div class="info custom-block"><p class="custom-block-title">Atomicity</p><p>All these steps happen within a single Database Transaction. If any step fails (e.g., stock runs out during the process), the entire operation is rolled back.</p></div><hr><h2 id="_2-multi-warehouse-inventory" tabindex="-1">2. Multi-Warehouse Inventory <a class="header-anchor" href="#_2-multi-warehouse-inventory" aria-label="Permalink to &quot;2. Multi-Warehouse Inventory&quot;">​</a></h2><p>Stock is tracked at the <strong>Product Variant</strong> level across multiple <strong>Warehouses</strong>.</p><ul><li><strong><code>on_hand</code></strong>: Physical stock present in the warehouse.</li><li><strong><code>reserved</code></strong>: Items currently in a customer&#39;s checkout process but not yet paid.</li><li><strong><code>available</code></strong>: <code>on_hand - reserved</code>. This is what the API returns to customers.</li></ul><h3 id="stock-movement-logs" tabindex="-1">Stock Movement Logs <a class="header-anchor" href="#stock-movement-logs" aria-label="Permalink to &quot;Stock Movement Logs&quot;">​</a></h3><p>Every single stock change (manual adjustment, order placement, return) is recorded in the <code>stock_logs</code> table with before/after quantities. This creates an immutable audit trail for warehouse managers.</p><h3 id="inventory-guards" tabindex="-1">Inventory Guards <a class="header-anchor" href="#inventory-guards" aria-label="Permalink to &quot;Inventory Guards&quot;">​</a></h3><ul><li><strong>Deduction protection</strong>: <code>InventoryService::deduct()</code> throws <code>InsufficientStockException</code> if the requested quantity exceeds <code>quantity_on_hand</code>, preventing negative stock.</li><li><strong>Reservation flow</strong>: <code>reserve()</code> moves stock from available to reserved, <code>release()</code> reverses it. Both operations are atomic.</li><li><strong>Audit trail</strong>: Every stock movement is logged in <code>stock_logs</code> with <code>quantity_before</code> and <code>quantity_after</code>.</li></ul><hr><h2 id="_3-promotions-pricing-engine" tabindex="-1">3. Promotions &amp; Pricing Engine <a class="header-anchor" href="#_3-promotions-pricing-engine" aria-label="Permalink to &quot;3. Promotions &amp; Pricing Engine&quot;">​</a></h2><p>LaraCommerce implements a multi-layered pricing strategy:</p><ol><li><strong>Base Price</strong>: Set on the product or variant.</li><li><strong>Comparison Price</strong>: Used for &quot;original price&quot; strike-through display.</li><li><strong>Promotions</strong>: Automatic cart-level or product-level discounts based on date ranges and categories.</li><li><strong>Coupons</strong>: Manual codes applied by the user (Percentage, Fixed, Free Shipping, Buy-X-Get-Y).</li><li><strong>Price Tiers</strong>: Bulk discounts based on quantity (e.g., Buy 10+ for 15% off).</li></ol><p><strong>Priority</strong>: Coupons are applied <em>after</em> promotion prices are calculated.</p><h3 id="buy-x-get-y-coupons" tabindex="-1">Buy-X-Get-Y Coupons <a class="header-anchor" href="#buy-x-get-y-coupons" aria-label="Permalink to &quot;Buy-X-Get-Y Coupons&quot;">​</a></h3><p>The <code>buy_x_get_y</code> coupon type implements real cart-aware logic:</p><ul><li>Identifies the cheapest eligible items in the cart as the &quot;free&quot; items</li><li>Applies the coupon&#39;s percentage value as discount on those free items</li><li>Falls back to a simple percentage discount if coupon metadata (<code>buy_quantity</code>, <code>get_quantity</code>) is not configured</li></ul><hr><h2 id="_4-stripe-payment-lifecycle" tabindex="-1">4. Stripe Payment Lifecycle <a class="header-anchor" href="#_4-stripe-payment-lifecycle" aria-label="Permalink to &quot;4. Stripe Payment Lifecycle&quot;">​</a></h2><p>We use the <strong>Stripe PaymentIntents API</strong>, which is the most secure and modern way to handle payments.</p><ul><li><strong><code>createIntent</code></strong>: Creates a PaymentIntent on Stripe and a <code>Payment</code> record in our DB with <code>pending</code> status. Supports pre-selecting a saved card via <code>payment_method_id</code>.</li><li><strong>Idempotency</strong>: Each PaymentIntent creation uses a unique idempotency key to prevent duplicate charges on retry.</li><li><strong>Webhooks</strong>: We listen for 6 event types: <code>payment_intent.succeeded</code>, <code>payment_intent.payment_failed</code>, <code>payment_intent.requires_action</code>, <code>charge.refunded</code>, <code>charge.dispute.created</code>, and <code>refund.updated</code>.</li><li><strong>Refunds</strong>: Handled via <code>RefundService</code>, which calls the Stripe API and creates a corresponding <code>Refund</code> record and <code>Transaction</code> log in our system.</li><li><strong>Refund Validation</strong>: Before processing, the system validates that the refund amount is positive and does not exceed the original payment amount.</li><li><strong>3D Secure</strong>: If a card requires authentication, the API returns a <code>requires_action</code> status, which the mobile/web frontend uses to trigger the Stripe authentication modal. A push notification is sent to the customer.</li><li><strong>Disputes</strong>: Stripe <code>charge.dispute.created</code> events are captured and logged as <code>dispute</code> transactions for admin review.</li><li><strong>Deduplication</strong>: Webhook events are cached for 48 hours to prevent double-processing.</li></ul><hr><h2 id="_5-refunds-returns-rma" tabindex="-1">5. Refunds &amp; Returns (RMA) <a class="header-anchor" href="#_5-refunds-returns-rma" aria-label="Permalink to &quot;5. Refunds &amp; Returns (RMA)&quot;">​</a></h2><p>The Return Merchandise Authorization flow:</p><ol><li>Customer requests a return for specific items.</li><li>Admin reviews and <strong>approves</strong> or <strong>rejects</strong> the request.</li><li>Once items are received, admin marks them as <strong>received</strong>, which automatically triggers the <code>RefundService</code>.</li><li>Refunds can be issued to the <strong>original payment method</strong> (Stripe) or to the internal <strong>Wallet balance</strong>.</li></ol><p>Additionally, when a <strong>shipment</strong> is marked as <code>returned</code> by the carrier, the <code>ShipmentController</code> automatically updates the parent order&#39;s status to <code>returned</code>.</p><h3 id="refund-safeguards" tabindex="-1">Refund Safeguards <a class="header-anchor" href="#refund-safeguards" aria-label="Permalink to &quot;Refund Safeguards&quot;">​</a></h3><ul><li>Refund amount must be greater than zero</li><li>Refund amount cannot exceed the original payment amount (<code>REFUND_EXCEEDS_PAYMENT</code> error)</li><li>Wallet refunds credit the user&#39;s balance atomically with a pessimistic lock</li></ul><hr><h2 id="_6-wallet-system" tabindex="-1">6. Wallet System <a class="header-anchor" href="#_6-wallet-system" aria-label="Permalink to &quot;6. Wallet System&quot;">​</a></h2><p>Each user has an internal wallet created automatically on registration by the <code>UserObserver</code>.</p><ul><li><strong>Credits &amp; Debits</strong> use pessimistic locking (<code>SELECT ... FOR UPDATE</code>) to prevent race conditions on concurrent operations.</li><li><strong>Balance tracking</strong>: Every transaction records <code>balance_before</code> and <code>balance_after</code> for a complete audit trail.</li><li><strong>Debit guard</strong>: Debits are rejected with <code>INSUFFICIENT_WALLET_BALANCE</code> if the balance is too low.</li><li><strong>Wallet deactivation</strong>: Inactive wallets cannot be debited.</li></ul>',39)])])}const p=t(i,[["render",n]]);export{g as __pageData,p as default};
